+}
+
+.btn-page {
+    background: #fff;
+    border: 1px solid #dee2e6;
+    padding: 0.4rem 0.75rem;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-page.active {
+    background-color: #0d6efd;
+    color: white;
+    border-color: #0d6efd;
+}
+
+.btn-page:hover:not(:disabled):not(.active) {
